import React, { useState } from "react";
import { Imgdb, Namedb } from "../components/firebase_setup";
import { v4 } from "uuid";
import { getDownloadURL, ref, uploadBytes } from "firebase/storage";
import { addDoc, collection } from "firebase/firestore";

function Home(){

    const [Txt, setTxt] = useState("");
    const [img, setimg] = useState("");


    const handleimgUpload=(e) =>{
        console.log(e.target.files[0]);
        const imgs = ref(Imgdb,`ImgsFile/${v4()}`);
        uploadBytes(imgs, e.target.files[0]).then(data=>
            getDownloadURL(data.ref).then(val=>{
                setimg(val);
            }) 
        )
    }

    const handleinput = async ()=> {
        const valRef = collection(Namedb,"txtData")
        await addDoc(valRef,{txtval:Txt,imgUrl:img})
    }


    const handleLogout =()=>{
        localStorage.clear()
        window.location.reload()
    }


    return(
        <div>
            <h1>This is a placeholder Homepage for Catsa!!!!</h1>
            <section className="upload">
                <input className="textbox" onChange={(e)=>setTxt(e.target.value)}/><br/>
                <input className="ProfilePic" type="file" onChange={(e)=>handleimgUpload(e)} /><br/>
                <button className="profileAdd" onClick={handleinput}>Done!</button>
            </section>
            <button className="Logoutbut" onClick={handleLogout}>Logout</button>
        </div>
    );
}

export default Home;
